A comparison of stack allocation vs heap allocation in game scopes:

```cpp
class FTransform {
public:
    float X = 0.0f, Y = 0.0f, Z = 0.0f;
};

class AActor {
public:
    FTransform ActorTransform;
};

void SpawnExample() {
    // Stack Allocation: Local transform destroyed automatically when function ends
    FTransform LocalTransform;
    LocalTransform.X = 10.0f;

    // Heap Allocation: Persistent actor remains in memory until manually deleted
    AActor* SpawnedActor = new AActor();
    SpawnedActor->ActorTransform = LocalTransform;

    // Cleanup heap to prevent memory leak
    delete SpawnedActor;
}
```
